    return new Iterator<Chromosome>() {
        private final Iterator<Chromosome> delegate = chromosomes.iterator();

        @Override
        public boolean hasNext() {
            return delegate.hasNext();
        }

        @Override
        public Chromosome next() {
            return delegate.next();
        }

        @Override
        public void remove() {
